# -*- coding: utf-8 -*-
"""Jismoniy tarbiya - 20 mavzulik konspekt"""
import zipfile, datetime
TOPICS = []
def esc(t): return t.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace('"',"&quot;")
def run(text,bold=False,size=28,font="Times New Roman"):
    rpr='<w:rPr><w:rFonts w:ascii="%s" w:hAnsi="%s" w:cs="%s"/>'%(font,font,font)
    if bold: rpr+='<w:b/><w:bCs/>'
    rpr+='<w:sz w:val="%d"/><w:szCs w:val="%d"/></w:rPr>'%(size,size)
    return '<w:r>%s<w:t xml:space="preserve">%s</w:t></w:r>'%(rpr,esc(text))
def para(text,bold=False,size=28,align="both",indent_first=709,space_after=120,line=360,keep_next=False):
    ppr='<w:pPr>'
    if keep_next: ppr+='<w:keepNext/>'
    ppr+='<w:spacing w:after="%d" w:line="%d" w:lineRule="auto"/>'%(space_after,line)
    if indent_first: ppr+='<w:ind w:firstLine="%d"/>'%indent_first
    ppr+='<w:jc w:val="%s"/></w:pPr>'%align
    return '<w:p>%s%s</w:p>'%(ppr,run(text,bold=bold,size=size))
def page_break(): return '<w:p><w:r><w:br w:type="page"/></w:r></w:p>'
def empty_para(): return '<w:p><w:pPr><w:spacing w:after="0" w:line="360" w:lineRule="auto"/></w:pPr></w:p>'
def build_topic(t,is_first):
    parts=[]
    if not is_first: parts.append(page_break())
    parts.append(para("%d-MAVZU. %s"%(t["num"],t["title"].upper()),bold=True,size=30,align="center",indent_first=0,space_after=180,keep_next=True))
    parts.append(para("Reja:",bold=True,size=28,align="left",indent_first=0,space_after=60,keep_next=True))
    for i,r in enumerate(t["reja"],1): parts.append(para("%d. %s"%(i,r),size=28,align="left",indent_first=360,space_after=40))
    parts.append(empty_para())
    for idx,(head,paras) in enumerate(t["sections"],1):
        parts.append(para("%d. %s"%(idx,head),bold=True,size=28,align="left",indent_first=0,space_after=80,keep_next=True))
        for p in paras: parts.append(para(p,size=28,align="both",indent_first=709,space_after=120))
    return "".join(parts)
def build_document():
    body="".join(build_topic(t,i==0) for i,t in enumerate(TOPICS))
    sect='<w:sectPr><w:pgSz w:w="11906" w:h="16838"/><w:pgMar w:top="1134" w:right="850" w:bottom="1134" w:left="1701" w:header="708" w:footer="708" w:gutter="0"/><w:pgNumType w:start="1"/></w:sectPr>'
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><w:body>'+body+sect+'</w:body></w:document>'
CT='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/><Override PartName="/docProps/core.xml" ContentType="application/vnd.openxmlformats-package.core-properties+xml"/><Override PartName="/docProps/app.xml" ContentType="application/vnd.openxmlformats-officedocument.extended-properties+xml"/></Types>'
RE='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/><Relationship Id="rId2" Type="http://schemas.openxmlformats.org/package/2006/relationships/metadata/core-properties" Target="docProps/core.xml"/><Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/extended-properties" Target="docProps/app.xml"/></Relationships>'
DR='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/></Relationships>'
ST='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/><w:lang w:val="uz-Latn-UZ"/></w:rPr></w:rPrDefault><w:pPrDefault><w:pPr><w:spacing w:line="360" w:lineRule="auto"/></w:pPr></w:pPrDefault></w:docDefaults><w:style w:type="paragraph" w:default="1" w:styleId="Normal"><w:name w:val="Normal"/><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr></w:style></w:styles>'
def cp():
    n=datetime.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>20 mavzu</dc:title><dc:creator>Konspekt</dc:creator><dcterms:created xsi:type="dcterms:W3CDTF">%s</dcterms:created><dcterms:modified xsi:type="dcterms:W3CDTF">%s</dcterms:modified></cp:coreProperties>'%(n,n)
AP='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Properties xmlns="http://schemas.openxmlformats.org/officeDocument/2006/extended-properties"><Application>Konspekt</Application></Properties>'
def write_docx(path):
    with zipfile.ZipFile(path,"w",zipfile.ZIP_DEFLATED) as z:
        z.writestr("[Content_Types].xml",CT); z.writestr("_rels/.rels",RE)
        z.writestr("word/document.xml",build_document()); z.writestr("word/_rels/document.xml.rels",DR)
        z.writestr("word/styles.xml",ST); z.writestr("docProps/core.xml",cp()); z.writestr("docProps/app.xml",AP)
    print("OK:",path,"|",len(TOPICS),"mavzu")

TOPICS.append({"num":1,"title":"Umumrivojlantiruvchi mashqlar","reja":["Umumrivojlantiruvchi mashqlar tushunchasi va ahamiyati.","Mashqlarning tasnifi va tuzilishi.","Asosiy umumrivojlantiruvchi mashqlar.","Mashqlarni bajarish metodikasi."],"sections":[("Umumrivojlantiruvchi mashqlar tushunchasi va ahamiyati",["Umumrivojlantiruvchi mashqlar (URM) — barcha mushak guruhlarini har tomonlama rivojlantirishga qaratilgan, har xil murakkablikdagi va yo'nalishdagi jismoniy mashqlardir. Ular jismoniy tarbiya va sport mashg'ulotlarining ajralmas qismi hisoblanadi.","URM larning ahamiyati katta: ular asosiy jismoniy sifatlarni rivojlantiradi, tana harakatchanligini oshiradi, qon aylanishi va nafas tizimini faollashtiradi, organizmni keyingi yuklamalarga tayyorlaydi va shikastlanishlardan saqlaydi.","URM lar har xil yoshdagi va tayyorgarlik darajasidagi shug'ullanuvchilar uchun mos: bolalardan tortib qariyalargacha. Ular maxsus jihoz talab qilmaydi va istalgan joyda bajarilishi mumkin — uyda, sport zalida, tabiatda. Bu URM larning universalligini ko'rsatadi."]),("Mashqlarning tasnifi va tuzilishi",["Mashqlar tasnifi: 1) gavda qismi bo'yicha (qo'l, oyoq, gavda, bosh uchun), 2) yo'nalishi bo'yicha (egilish, yoyilish, aylanish), 3) bajarilish usuli bo'yicha (turgan holatda, o'tirib, yotib), 4) maqsadi bo'yicha (kuch, egiluvchanlik, koordinatsiya), 5) jihozdan foydalanish bo'yicha.","Boshlang'ich pozitsiyalar (BP) muhim: oyoqlar yelka kengligida, qollar belda yoki tepada, gavda tik. To'g'ri BP mashqning samaradorligini va xavfsizligini ta'minlaydi. Har bir mashq aniq BP dan boshlanadi.","Mashq tuzilishi: 1) BP qabul qilish, 2) tayyorlov harakati, 3) asosiy harakat, 4) yakuniy harakat (BP ga qaytish), 5) takrorlash. Mashqlar 4-8 hisobiga bajariladi va 6-12 marta takrorlanadi (yosh va tayyorgarlikga qarab)."]),("Asosiy umumrivojlantiruvchi mashqlar",["Bosh va bo'yin uchun: bosh aylanishi, oldinga-orqaga egilish, yon tomonga egilish. Bu mashqlar bo'yin mushaklarini bo'shashtiradi va qon aylanishini yaxshilaydi. Ehtiyotkorlik bilan, sekin bajariladi.","Qo'l va yelka uchun: qo'l aylanishi (oldinga, orqaga), yelka aylanishi, qo'l silkitish, qo'lni tepaga ko'tarish va tushirish. Bu mashqlar yelka bo'g'imining harakatchanligini oshiradi va qo'l mushaklarini isitadi.","Gavda uchun: oldinga, orqaga, yonga egilish; gavda aylanishi; 'mostik' mashqlari. Oyoqlar uchun: cho'kib turish (squat), oyoq aylanishi, oyoqni ko'tarish, sakrash mashqlari. Bu mashqlar yo'lakda yoki guruhda bajariladi."]),("Mashqlarni bajarish metodikasi",["Mashqlar engildan og'irga, oddiydan murakkabga ketma-ketlikda bajariladi. Avval bosh va qo'l uchun, keyin gavda, keyin oyoqlar uchun mashqlar. Yuklama bosqichma-bosqich oshiriladi: avval kichik amplituda, keyin to'liq amplituda.","Nafas olish to'g'ri tashkil etiladi: harakat boshida nafas olish, harakat oxirida nafas chiqarish. Yoki ritmik nafas olish saqlanadi. Nafasni tutish ta'qiqlanadi — bu zararli.","Mashqlar guruhli (musiqa ostida, hisobiga) yoki yakka tartibda bajariladi. Ular har gal mashg'ulotda ishlatiladi — qizdiruv qismida (5-10 daqiqa) yoki alohida mashg'ulot sifatida (utrenniya gimnastika)."])],})

TOPICS.append({"num":2,"title":"Tayanib sakrash. Tirmashib chiqish","reja":["Tayanib sakrash texnikasi.","Tirmashib chiqish turlari va texnikasi.","Sakrash va tirmashish mashqlari.","Xavfsizlik qoidalari va sug'urta."],"sections":[("Tayanib sakrash texnikasi",["Tayanib sakrash (oporno-prыgkovыe uprajneniya) — sportchining qo'l tayanib biror to'siq yoki snaryad ustidan sakrash mashqidir. U gimnastika va akrobatikaning muhim elementi hisoblanadi va kuch, koordinatsiya hamda jasorat talab qiladi.","Tayanib sakrash bosqichlari: 1) yugurib kelish (4-8 qadam), 2) trampolinga sakrash (bir oyoq bilan), 3) tayanish (qo'llar bilan to'siqqa tegish), 4) parvoz (gavdani uloqtirish), 5) tushish (yumshoq, ikki oyoqqa). Har bir bosqich aniq bajariladi.","Asosiy turlari: oyoqlar yon tomonda (straddle vault — kozyol bo'ylab), oyoqlar bukilgan (squat vault), gavdani yoyilgan (handspring), parvoz va aylanish (Yamashita, Tsukahara). Bular murakkablik darajasi bo'yicha tartiblangan."]),("Tirmashib chiqish turlari va texnikasi",["Tirmashib chiqish (lazaniya) — qo'l va oyoq kuchidan foydalanib vertikal yuzaga ko'tarilish mashqidir. Bu kuch, chidamlilik va jasoratni rivojlantiradi. Asosan qo'l mushaklari, kor va oyoq mushaklari ishlaydi.","Asosiy turlar: arqonda tirmashib chiqish (faqat qo'l, qo'l va oyoq, prelash usulida), shest tepasiga chiqish, gimnastik devorda (shvedstenkada) ko'tarilish va tushish, kanat zinapoyasida chiqish. Har biri o'z texnikasiga ega.","Arqonda chiqish texnikasi: 'qo'l va oyoq' usulida — qo'llar arqonni tutadi, oyoqlar arqonni quchoqlaydi va itariladi; 'faqat qo'l' usulida — bu og'irroq, uzaytirib qo'l bilan bir-birga ko'tariladi. Tushishda boshqarilgan tezlik kerak."]),("Sakrash va tirmashish mashqlari",["Sakrash uchun maxsus mashqlar: trampolinda sakrashlar (turli pozitsiyalarda — turli oyoq harakatlari), kichik to'siqlardan sakrash (50-80 sm), uzun va baland sakrash (qulayligi bilan kozyol bo'ylab). Bu mashqlar tayyorgarlik bosqichlari hisoblanadi.","Tirmashib chiqish uchun mashqlar: tortilish (tortilishlardan tushish - eccentric pull-ups), yotgan holatdan tortilish (inverted rows), qo'l kuchini rivojlantiruvchi mashqlar (bicep curl, hammer curl), pal'sa va flag mashqlari (ilg'or sportchilar uchun).","Yordamchi mashqlar: kor mushaklarini mustahkamlash (plank, leg raises), oyoq kuchi (squat, lunge), egiluvchanlik mashqlari. Komleks tayyorgarlik tirmashib chiqishni osonlashtiradi va xavfsizroq qiladi."]),("Xavfsizlik qoidalari va sug'urta",["Xavfsizlik qoidalari: faqat tajribali murabbiy rahbarligida bajarish, yetarli qizdiruv (10-15 daqiqa), gilamlar va matlar (yumshoq tushish uchun), faqat o'z imkoniyatiga mos elementlarni urinib ko'rish, charchaganda to'xtash.","Sug'urta texnikasi: murabbiy yoki yordamchi sug'urtalovchining tayanib sakrashda sportchini ko'krak ostidan tutish, muvozanatni saqlashga yordam berish; tirmashib chiqishda — pastdan kuzatib turish, yiqilish ehtimolida tutish.","Jihozlarni tekshirish: arqonlar va shestlar mustahkamligini tekshirish (zarari, ilonish bo'lmasligi), gimnastik devor mahkamligini, kozyol va konning barqarorligini, gilam yumshoqligini. Har gal mashg'ulot oldidan jihozlar tekshiriladi."])],})

TOPICS.append({"num":3,"title":"Osilishlar. Tayanishlar","reja":["Osilish va tayanish tushunchasi.","Asosiy osilish turlari.","Tayanish turlari va bajarilishi.","Mashqlar metodikasi va xavfsizlik."],"sections":[("Osilish va tayanish tushunchasi",["Osilish (vis) va tayanish (upor) — gimnastikaning asosiy elementlari. Osilishda sportchining tana og'irligi qo'llarda osilgan holatda saqlanadi (oyoqlar yerda emas). Tayanishda esa qo'llar pastga ishlaydi va gavda qo'llardan yuqorida turadi.","Bu elementlar gimnastik snaryadlarda (turnik, brus, halqalar) bajariladi va qo'l, ko'krak, orqa va kor mushaklarini mustahkamlaydi. Ular gimnastika bo'yicha murakkab elementlar uchun zaruriy tayyorgarlik hisoblanadi.","Osilish va tayanish jismoniy tarbiya darslarida turli yoshdagi talabalar uchun foydalidir: ular qo'l kuchini rivojlantiradi, gavda muskulaturasini mustahkamlaydi va tana ustidan nazorat qobiliyatini oshiradi."]),("Asosiy osilish turlari",["1) Oddiy osilish (prostoy vis) — qo'llar tik, gavda osilgan, oyoqlar erkin. 2) Yon osilish (smeshanniy vis) — bir oyoq snaryadda, ikkinchisi osilgan. 3) Bukilgan oyoqli osilish (vis sognuvshis) — oyoqlar belga ko'tarilgan. 4) Teskari osilish (vis prognuvshis) — oyoqlar tepaga, bosh pastga.","5) Burchak ostida osilish (ugol v vise) — oyoqlar gavdaga 90 daraja burchak hosil qiladi. 6) Yopiq osilish (vis sognuvshisya) — oyoqlar yelkaga yaqin. Har bir osilish mushaklarni boshqacha ishlatadi va o'z murakkablik darajasiga ega.","Osilishdagi mashqlar: tortilish (pull-up — eng asosiy), oyoqlarni ko'tarish (leg raises — kor uchun), gavdani burish, oyoq aylantirish, oyoqni gorizontal saqlash (front lever — ilg'or). Bu mashqlar kuch va chidamlilikni rivojlantiradi."]),("Tayanish turlari va bajarilishi",["1) Oddiy tayanish (prostoy upor) — qo'llar tik, gavda tepada, oyoqlar to'g'ri. 2) Yelkalar tayanishi (upor na predplech'yax) — bilaklarda tayanish, brusda. 3) Tirsak tayanishi — tirsaklarda. 4) Qo'l yelkalari tayanishi (uglovoy upor) — gavda tik, oyoqlar oldinga.","5) Burchak ostida tayanish (ugol v upore) — oyoqlar gavdaga 90 daraja, qo'llar tik. Bu element kor va qo'l kuchini chuqur talab qiladi. 6) 'Krest' (krest na kol'tsax) — halqalarda qo'llar yon tomonda, gavda osilgan; bu juda qiyin element.","Tayanishdagi mashqlar: dips (qo'lqop ko'tarish-tushish), pushki tayanish, bryusda harakatlar (mahi v upore), halqalarda oyoqlarni ko'tarish, planche. Bu mashqlar yelka va ko'krak kuchini rivojlantiradi."]),("Mashqlar metodikasi va xavfsizlik",["Metodika: oddiydan murakkabga, kichikdan kattaga. Avval pastki turnikda (yer yaqinida), keyin yuqori turnikda. Avval tutib o'rganish, keyin mustaqil. Birinchi marta sug'urta bilan, keyin mustaqil.","Mushaklarni tayyorlash: qo'l kuchini bosqichma-bosqich oshirish, ushlash kuchini (grip strength) rivojlantirish, kor mushaklarini mustahkamlash. Ko'p o'rgancchilar uchun haftada 3 marta tayanish va osilish mashqlari yetarli.","Xavfsizlik: snaryadlarning mahkamligini tekshirish, gilam yoki yumshoq tushish joyini tayyorlash, qo'l yorilishidan saqlash uchun magneziy va to'g'ri ushlash, charchaganda to'xtash, yiqilishdan oldin xavfsiz tushishni o'rganish."])],})

TOPICS.append({"num":4,"title":"Akrobatika. Muvozanatni saqlash mashqlari","reja":["Akrobatika tushunchasi va turlari.","Asosiy akrobatik elementlar.","Muvozanat va uni saqlash mashqlari.","Akrobatika va muvozanat metodikasi."],"sections":[("Akrobatika tushunchasi va turlari",["Akrobatika — gavdaning fazoda burilishi, aylanishi va parvozi bilan bog'liq mashqlar majmuasidir. So'z yunoncha 'akrobates' (yuqorida yuruvchi) dan kelib chiqqan. Akrobatika nafaqat sport, balki sirk va san'atda ham keng qo'llaniladi.","Akrobatika turlari: 1) yer ustidagi akrobatika (yer ustida elementlar — umbalovlar, sakrashlar), 2) jismoniy akrobatika (juftlikda yoki guruhda — minoralar, balanslar), 3) sport akrobatikasi (rasmiy musobaqa turi — Olimpiadaga kirmagan, lekin Jahon chempionatlari bor), 4) batutda akrobatika (Olimpiya turi).","Akrobatika ko'p sohalarda foydalaniladi: gimnastika, sport gimnastikasi, badiiy gimnastika, futbol darvozaboni, tushuvchilar (paratroopers), sirk artistlari, askarlar va boshqalar. U koordinatsiya, jasorat va aniqlik talab qiladi."]),("Asosiy akrobatik elementlar",["1) Umbalov (kuvyrok) — oldinga va orqaga: tana boshdan dumg'azaga aylanadi. 2) 'Tepa o'rta' (kolesi, cartwheel) — yon tomonga aylanish qo'l-oyoq tutib. 3) 'Mostik' (mostik) — orqaga eguilib, qo'llar yer ga tegadi. 4) 'Shpagat' (shpagat) — oyoqlarni to'liq yoyish (oldinga yoki yon tomonga).","5) 'Qayichi' (stoyka na rukax) — qo'llarda turish, gavda to'g'ri. 6) 'Boshda turish' (stoyka na golove) — bosh va qo'llarda turish. 7) 'Flik-flak' (flik) — orqaga sakrash qo'lda tepish. 8) Salto — orqaga, oldinga, yon tomonga aylanish; turli pozitsiyalarda (tug, pike, layout).","Bu elementlar zinama-zina o'rganiladi: avval oddiy umbalov, keyin tepa o'rta, mostik, qayichi, va nihoyat saltolar. Har bir element mukammal egallanmaguncha keyingisiga o'tilmaydi. Ko'p mashq talab etadi."]),("Muvozanat va uni saqlash mashqlari",["Muvozanat (rovnovesie) — tana og'irlik markazini muayyan tayanish maydoni ustida saqlash qobiliyatidir. Ikki turi bor: statik muvozanat (turgan joyda saqlash) va dinamik muvozanat (harakat davomida saqlash).","Statik muvozanat mashqlari: 'lastochka' (qarldug'ach — bir oyoqda turish, ikkinchisi orqada), 'zhuravl'' (turna — bir oyoq baland), bir oyoqda ko'z yumib turish, qayichi va boshda turish, jurnalda (gimnastik nogga) yoki tasmada turish.","Dinamik muvozanat mashqlari: tor chiziq bo'ylab yurish, gimnastik nogga (balka)da yurish — to'g'ri, orqaga, yon tomonga, ko'z yumib; mukomil gilam ustida harakat (slackline); buzilgan yer ustidan yurish. Bu mashqlar ichki quloq vestibulyar tizimini rivojlantiradi."]),("Akrobatika va muvozanat metodikasi",["Akrobatik elementlar bosqichma-bosqich o'rgatiladi: 1) ko'rsatish va tushuntirish, 2) yengil sharoitda mashq qilish (yumshoq mat, sug'urta bilan), 3) takrorlash, 4) mustaqil bajarish, 5) takomillashtirish (turli sharoitlarda).","Sug'urta — akrobatikada kalit: murabbiy doim yonda turadi va kerak bo'lganda sportchini ushlaydi (ko'krak ostidan, beldan, dumg'azadan). Lonzha (kabel sug'urtasi) murakkab elementlar uchun ishlatiladi.","Muvozanatni rivojlantirish — bolaligidan boshlanadigan jarayon. Maxsus mashqlar bilan u har yoshda yaxshilanishi mumkin. Yuqori darajadagi muvozanat ko'p sport turlarida (gimnastika, figurali uchish, akrobatika, kurash) g'oliblikning kalitidir."])],})

TOPICS.append({"num":5,"title":"Yugurish","reja":["Yugurish tushunchasi va uning turlari.","Yugurish texnikasi.","Yugurishga tayyorgarlik usullari.","Yugurishning sog'liq uchun foydalari."],"sections":[("Yugurish tushunchasi va uning turlari",["Yugurish — har ikki oyoqning navbatma-navbat yer dan ajralib, parvoz fazasidan o'tib, yana yerga tushishi bilan ifodalanadigan tabiiy harakat turidir. Yugurish — eng qadimgi va ommaviy jismoniy faoliyat shakli.","Yugurish turlari masofaga ko'ra: sprint (qisqa masofa — 60m, 100m, 200m, 400m), o'rta masofa (800m, 1500m, 1000m), uzoq masofa (3000m, 5000m, 10000m), marafon (42,195km), o'ta marafon (50km dan katta). Boshqa: krossda (tabiatda), to'siqlar bilan (steeplechase), to'siqdan oshib (hurdles).","Yugurish nafaqat sport, balki sog'lomlashtirish vositasi sifatida ham keng tarqalgan. Million odamlar har kuni yugurish bilan shug'ullanishadi — bu jismoniy va ruhiy salomatlik uchun foydalidir. Yugurishga maxsus joy yoki jihoz kerak emas."]),("Yugurish texnikasi",["To'g'ri yugurish texnikasi: gavda biroz oldinga egilgan (5-10 daraja), bosh tik, ko'z 5-10 metr oldinga; oyoqlar tovon yoki to'liq oyoq bilan yerga tegadi (sprintda barmoq uchi); qadam uzunligi va chastotasi optimal nisbatda; qo'llar tirsakdan 90 daraja bukilgan, ritmik tebranadi.","Sprint texnikasi: yuqori qadam chastotasi (5-6 qadam soniyasiga), qadam uzunligi katta, oyoqlar barmoq uchi bilan yerga tegadi, gavda yuqori egilish (30-45 daraja startda). Qo'llar tez ishlaydi.","Uzoq masofa texnikasi: tejamli, ravon harakat. Qadam o'rtacha, oyoqlar tovon-aralash yer ga tegadi. Nafas olish ritmik (2:2 yoki 3:3 qadam-nafas nisbatida). Energiya tejaladi — chunki masofa uzun."]),("Yugurishga tayyorgarlik usullari",["Bazaviy chidamlilik: uzoq, sekin yugurish (long slow distance — LSD). Bu yurak-qon tomir tizimini rivojlantiradi va asos quradi. Boshlang'ich uchun 20-30 daqiqa, malakalilar 60+ daqiqa.","Tezlik mashqlari: interval (yuksak intensiv qisqa qismlar — 200-400m, dam bilan navbatlanadi), tempo run (o'rtacha tezlikda 20-40 daqiqa), fartlek ('tezlik o'yini' — turli tezlikda erkin yugurish), qisqa sprintlar (50-100m).","Maxsus mashqlar: tepalikka yugurish (kuchni rivojlantiradi), qadam mashqlari (drill — high knees, butt kicks), strides (60-100m yengil sprintlar), kuch mashqlari (squat, lunge, plyometrics)."]),("Yugurishning sog'liq uchun foydalari",["Jismoniy foydalari: yurak mushaklarini mustahkamlaydi (yurak markaziyligi pasayadi), qon bosimini boshqaradi, xolesterin darajasini yaxshilaydi, ortiqcha vaznni kamaytiradi (300-700 kkal soatiga), suyak zichligini oshiradi, immunitetni mustahkamlaydi.","Ruhiy foydalari: stress va depressiyani kamaytiradi (endorfinlar 'baxt gormonlari' ajratadi), uyqu sifatini yaxshilaydi, miya faoliyatini kuchaytiradi (xotira va konsentratsiya), o'ziga ishonchni oshiradi va hayotga ijobiy munosabatni shakllantiradi.","Yugurishni boshlash: avval tibbiyotchi maslahatini olish, mos krossovkalar tanlash, asta-sekin oshirib borish (10% qoidasi haftalik hajm uchun), to'g'ri tashish bo'yicha qizdiruv qilish, suv ichish va ovqatlanishga e'tibor berish. Yugurish — umrli sog'liq garov."])],})

TOPICS.append({"num":6,"title":"Kross tayyorgarligi","reja":["Kross yugurish tushunchasi va xususiyatlari.","Kross trassasi va uning xususiyatlari.","Krossga tayyorgarlik usullari.","Kross musobaqalari va taktika."],"sections":[("Kross yugurish tushunchasi va xususiyatlari",["Kross (cross-country running) — tabiat sharoitida (o'rmon, dala, qir-adir) o'tkaziladigan yugurish musobaqasi. U yengil atletikadan farq qiladi — trassa tabiiy, har xil yuzaga ega. Kross qishki va kuzgi mavsumda ko'p o'tkaziladi.","Kross masofalari: erkaklar uchun 8-12 km, ayollar uchun 4-8 km, yoshlar uchun 2-6 km. Lekin bu masofalar musobaqaga qarab o'zgarishi mumkin. Trassa relyefi katta rol o'ynaydi — tepalik, pasaylik, balchiq, tosh, daryolar — barchasi qiyinchilik tug'diradi.","Kross — eng og'ir yugurish turlaridan biri: sportchi nafaqat tezlik va chidamlilikga ega bo'lishi, balki turli yer ko'rinishlariga moslashishi, tabiat hodisalariga (yomg'ir, sovuq, shamol) chidashi va ruhan barqaror bo'lishi kerak."]),("Kross trassasi va uning xususiyatlari",["Kross trassasi tabiiy o'rmon yo'lakidan, dala chiziqlaridan, qishloq yo'llaridan, ba'zan parklardan o'tadi. Trassa 1,5-2,5 km uzunligida bo'lib, bir necha marta aylantirilib chopiladi. Boshlanish va yakunlanish bir joyda.","Trassa belgilash: maxsus belgilar (lentochkalar, flagchalar, bo'yoq), yo'lkurslari, kontrol nuqtalari. Yarmida masofa belgilari bor (1km, 2km va h.k.) — sportchi tezligini boshqarish uchun.","Trassa qiyinchiliklari: tepalikka chiqish (kuch sarflanadi), pasaylikka tushish (xavfli — yiqilish ehtimoli), balchiq va suv (poyabzal og'irlashadi), tosh va shox-shabba (oyoq ehtiyot), o'tloqzor va o'rmon (notekis yer). Bularning hammasi tezlikni pasaytiradi va energiyani sarflaydi."]),("Krossga tayyorgarlik usullari",["Tayyorgarlik bazasi — uzoq yugurish (long runs): haftada 1 marta 60-90 daqiqa sekin tezlikda. Bu chidamlilik bazasini quradi va organizmni uzoq vaqt ishga tayyorlaydi.","Tepalik mashqlari (hill training): tepalikka qisqa va qattiq yugurish (200-400m), keyin pastga tushish — bu kuch va aerob quvvatni rivojlantiradi. Krossda tepaliklar ko'p uchragani uchun bu mashq juda muhim.","Maxsus krossda mashq: real trassa sharoitlarida yugurish — o'rmonda, daladagi yo'lakda, qor ustida (qishda). Bu poyabzalga, kiyimga, taktikaga moslashishni ta'minlaydi. Tabiatga kirgandagina trassa qiyinchiliklarini his qilish mumkin."]),("Kross musobaqalari va taktika",["Musobaqalar: maktab, universitet, shahar va respublika darajasidagi krossdar; xalqaro turnirlar (IAAF World Cross Country Championships); klub musobaqalari. Eng mashhur kross — Britaniyadagi 'English National Cross Country Championships' va Italiyadagi 'Cross della Vallagarina'.","Taktika: birinchi 1-2 km da pozitsiya egallash (oldinda yoki o'rta-orqada), o'rta qismida tezlikni saqlash va energiya tejash, oxirgi 1-2 km da hujum (sprint finish). Tepalikka chiqishda — tezlikni saqlamaslik, lekin ritmni buzmaslik. Pasaylikda — tezlanish.","Strategiyalar: 'oldinda yugurish' (front runner — tezlik bilan boshqarish), 'kuzatuvchi' (raqib orqasida turib oxirida sprint), 'guruhli yugurish' (peloton). Strategiya raqib va o'z imkoniyatlariga qarab tanlanadi. Tajriba va o'zlikni bilish muhim."])],})

TOPICS.append({"num":7,"title":"Sakrash","reja":["Sakrash tushunchasi va turlari.","Uzunlikka sakrash texnikasi.","Balandlikka sakrash texnikasi.","Sakrashga tayyorgarlik mashqlari."],"sections":[("Sakrash tushunchasi va turlari",["Sakrash (jumping) — tana og'irligini bir nuqtadan boshqasiga uloqtirish bilan bog'liq harakatdir. U yengil atletikaning muhim qismi va Olimpiya o'yinlari dasturida. Sakrash kuch, tezlik va texnikani talab qiladi.","Sakrash turlari: uzunlikka sakrash (long jump), balandlikka sakrash (high jump), uchburchak sakrash (triple jump), shest bilan sakrash (pole vault). Yana o'rinda sakrashlar (yoshlar uchun): turgan joydan uzunlikka, balandlikka.","Har bir sakrash turi o'z texnikasi va tayyorgarligini talab qiladi. Lekin barchasida umumiy elementlar bor: yugurib kelish (asos), itarish (asosiy oyoq bilan), parvoz (havoda), tushish (yumshoq, xavfsiz). Bu elementlarning sifati natijani belgilaydi."]),("Uzunlikka sakrash texnikasi",["Uzunlikka sakrash bosqichlari: 1) yugurib kelish (18-22 qadam, tezlikni oshirish), 2) itarish (oxirgi qadam — itarish chiziqdan), 3) parvoz (havoda — turli stillarda), 4) tushish (qum maydonchasiga, oldinga oyoq bilan).","Itarish texnikasi: oxirgi 4-6 qadamda tezlik maksimal bo'ladi, oxirgi qadam qisqaroq, kuchli oyoq bilan baland va oldinga itarish. Itarish burchagi 18-22 daraja optimal. Itarishdan keyin gavda tepaga ko'tariladi.","Parvoz stillari: 1) 'qadamlash' (chag stilya — oyoqlarni navbatma-navbat ko'tarish — havoda yugurishga o'xshash), 2) 'tepa eguilish' (visnaya stilya — gavda orqaga yoyiladi, oyoqlar oldinda), 3) 'qadam-eguilish' (kombinatsiya). Tushish — ikkala oyoqni oldinga olib, qum ga tushish."]),("Balandlikka sakrash texnikasi",["Balandlikka sakrash bosqichlari: 1) yugurib kelish (egri trayektoriyada, 6-10 qadam), 2) itarish (mahkam oyoqdan), 3) o'tish (planka ustidan), 4) tushish (mat ustiga). Maqsad — eng baland chiziqdan o'tish.","Stillar tarixi: 1) 'butla' (scissors — oyoqlar qaychi shaklida), 2) 'horine' (Western Roll — yon tomondan o'tish), 3) 'straddle' (oyoqlarni yoyib o'tish), 4) 'fosbury flop' (orqaga eguilib o'tish — Dik Fosburi 1968-yil ixtiro qilgan, hozir asosiy stil).","Fosbury flop texnikasi: yugurib kelish J shaklida (egri), itarish tashqi oyoqdan, gavda eguiladi orqaga (planka ustida), oyoqlar oxirgi navbatda ko'tariladi (ular planka ostida bo'ladi). Mat ustiga orqa bilan tushadi."]),("Sakrashga tayyorgarlik mashqlari",["Kuch mashqlari: chuqur cho'kib turish (deep squats), bir oyoqda cho'kib turish (pistol squats), 'lifts' (deadlifts), oyoq presi. Bu mashqlar oyoq mushaklarini kuchaytiradi va portlovchi kuchni rivojlantiradi.","Plyometrik mashqlar (eng samarali): vertikal sakrash (vertical jumps), uzun sakrash (long jumps), kassaga sakrash (box jumps), depth jumps (kassadan tushish va darhol sakrash), bounce drills (uzluksiz sakrashlar). Bu mashqlar mushak-pay reaksiyasini tezlashtiradi.","Texnik mashqlar: yugurib kelish ritmini topish (turli masofalarga qadamlash), itarish texnikasi (turgan joyda va yugurib kelishda), parvoz pozitsiyalarini mashq qilish (yog'ochda osilib turish, mat ustiga sakrash), tushish texnikasi. Texnika bilan kuch birlashganda yuqori natija bo'ladi."])],})

TOPICS.append({"num":8,"title":"Uloqtirish","reja":["Uloqtirish turlari va texnikasi.","Uloqtirish biomexanikasi.","Uloqtirish mashqlari.","Musobaqa qoidalari."],"sections":[("Uloqtirish turlari va texnikasi",["Uloqtirish — yengil atletikada snaryad (nayza, disk, yadro, bolg'a) ni imkon qadar uzoqqa otish bilan bog'liq sport turi. Har bir uloqtirish turi o'ziga xos texnika, kuch va koordinatsiyani talab qiladi.","Yadro itarish — 4-7,26 kg og'irlikdagi metall sharni doira ichidan itarib yuborish. Disk otish — 1-2 kg og'irlikdagi diskni aylanma harakat bilan uloqtirish. Nayza otish — 600-800g og'irlikdagi nayzani yugurib kelib otish. Bolg'a otish — 4-7,26 kg bolg'ani aylantrib otish.","Har bir turdagi texnika bosqichlari: tayyorgarlik pozitsiyasi, boshlang'ich tezlanish (aylanish yoki yugurish), asosiy zo'r berish (snaryad uloqtirilishi) va muvozanatni saqlash (doiradan chiqmaslik). To'g'ri texnika natijaga bevosita ta'sir qiladi."]),("Uloqtirish biomexanikasi",["Uloqtirishda fizika qonunlari ishlaydi: snaryad uchirilish burchagi (optimal 35-45 daraja), boshlang'ich tezlik (qancha tez — shuncha uzoq) va balandlik (qo'l balandligidan uloqtirish). Bu uchta omil masofani belgilaydi.","Kuch zanjiri tamoyili: oyoqlardan boshlangan kuch gavda orqali qo'lga va snaryad ga uzatiladi. Kuchli oyoqlar — asos, gavda aylanishi — tezlashtirish, qo'l — yakuniy impuls. Barcha bo'g'inlar ketma-ket ishlaydi.","Sportchining antropometrik ma'lumotlari muhim: uzun qo'l — katta leverage (kuch momenti), baland bo'y — yuqori uchirilish nuqtasi, og'ir tana — kuchli tayanch. Shuning uchun uloqtiruvchilar odatda baland va kuchli sportchilardir."]),("Uloqtirish mashqlari",["Kuch mashqlari: bench press, shoulder press, squat, deadlift, power clean. Bu mashqlar portlovchi kuchni rivojlantiradi. Plyometrik mashqlar: med-ball uloqtirish (turli yo'nalishlarda), sakrashlar, harakatlar.","Texnik mashqlar: engil snaryad bilan texnikani mashq qilish, turli masofadan otish, videoda tahlil. Maxsus mashqlar: aylanish texnikasi (diskda), yugurib kelish (nayzada), itarish texnikasi (yadroda). Har gal texnika aniqligiga e'tibor beriladi.","Umumiy mashqlar: gavda aylanish mashqlari, muvozanat mashqlari, egiluvchanlik. Yordamchi mashqlar: arqon tortish, rezinka bilan ishlash, partner bilan mashqlar. Bu barcha mashqlar birga qo'llanilganda yuqori natija beradi."]),("Musobaqa qoidalari",["Uloqtirish musobaqalari: har bir sportchiga 3-6 urinish beriladi (darajaga qarab). Eng uzoq natija hisobga olinadi. Uloqtirish sektori ichiga tushishi kerak (34,92 daraja sektor). Sektordan tashqariga tushgan natija hisobga olinmaydi.","Yadro itarishda: 2,135m diametrli doira ichidan itariladi, doiradan chiqish taqiqlangan. Disk va bolg'ada: qafas ichidagi doiradan otiladi (xavfsizlik uchun). Nayzada: yugurib kelib maxsus chiziqdan o'tmasdan otiladi.","O'lchash: uloqtirish joyi belgilanadi va masofa metalik lenta bilan o'lchanadi (doira ichki chekkasidan snaryad tushgan joyning eng yaqin nuqtasigacha). Zamonaviy musobaqalarda elektron o'lchash tizimlari qo'llaniladi."])],})

TOPICS.append({"num":9,"title":"Basketbol o'yini elementlari asosida turli texnik harakatlarni bajarish","reja":["Basketbolda individual texnik harakatlar.","Hujum texnikasi mashqlari.","Himoya texnikasi mashqlari.","Kompleks texnik mashqlar."],"sections":[("Basketbolda individual texnik harakatlar",["Basketbolda har bir o'yinchi quyidagi individual texnik harakatlarni egallashi kerak: driblling (to'pni yerga urib harakatlanish), passing (uzatish), shooting (savatga tashlash), rebounding (to'pni qaytarib olish) va footwork (oyoq harakati — pozitsiya o'zgartirish).","Driblling turlari: yuqori (tez harakatlanish uchun), past (himoyalash uchun), crossover (qo'l almashtirish), behind-the-back (orqa tomondan), between-the-legs (oyoq orasidan). Har biri muayyan vaziyatda qo'llaniladi. Bosh ko'tarilgan bo'lishi kerak — maydonga qarab harakatlanish.","Footwork — oyoq ishining to'g'riligi: defensive slide (yon harakatlar himoyada), pivot (bir oyoqda aylanish), jump stop (ikkala oyoqqa to'xtash), drop step (postsiyada harakatlanish). Bu ko'nikmalar hujum va himoyada asos bo'ladi."]),("Hujum texnikasi mashqlari",["Tashlash mashqlari: lay-up (ostidan yoritish — o'ng va chap qo'l bilan), jump shot (sakrab tashlash — turli masofadan), free throw (jarima tashlash — texnikani mustahkamlash), hook shot (ilmoq tashlash — post o'yinida). Har gal 50-100 tashlash mashq qilinadi.","Driblling mashqlari: konuslar orasida driblling (har xil tezlikda), ikkala qo'l bilan navbatma-navbat, ko'z yumib driblling (his qilish uchun), raqibga qarshi driblling (1v1 mashq). Maqsad — to'pni yo'qotmasdan istalgan yo'nalishda harakatlanish.","Uzatish mashqlari: juftlikda turli masofada (ko'krakdan, boshdan, polga, bir qo'ldan), harakat ichida uzatish (drive-and-kick), devordagi uzatish (wall passing). Aniqlik va tezlik — uzatishning ikki muhim sifati."]),("Himoya texnikasi mashqlari",["Himoya pozitsiyasi: oyoqlar yelkadan keng, tizzalar bukilgan, gavda past, qo'llar yoyilgan. Bu pozitsiya tez harakat qilish va raqibni to'xtatish imkonini beradi. Defensive slide — yon harakat himoya pozitsiyasida.","Himoya mashqlari: 1v1 himoya (raqibni to'p bilan harakatdan to'xtatish), close-out (tashqi o'yinchiga yaqinlashish), help defense (sherikka yordam), box-out (rebound uchun raqibni bloklash). Bu mashqlar jamoaviy himoyaning asosi.","Steal va block mashqlari: to'pni olish texnikasi (raqib driblling qilayotganda yoki uzatayotganda), tashlashni bloklash (sakrab, to'pga tegish). Bu mashqlar reaksiya tezligini va vaqtni to'g'ri aniqlash qobiliyatini talab qiladi."]),("Kompleks texnik mashqlar",["Kombinatsion mashqlar: driblling + tashlash (yugurib kelib lay-up), uzatish + tashlash (catch-and-shoot), pick-and-roll (ekran qo'yib harakatlanish). Bu mashqlar o'yindagi real vaziyatlarni imitatsiya qiladi.","Fast break (tez hujum) mashqi: 2v1, 3v2, 3v3 tez hujum situatsiyalari. Maqsad — raqib himoyaga qaytmasdan tez hujum qilish. Bu mashq tezlik, qaror qabul qilish va uzatish aniqligini rivojlantiradi.","Scrimmage (o'quv o'yini): to'liq o'yin sharoitida barcha texnik elementlarni qo'llash. Murabbiy o'yin davomida to'xtatib, vaziyatlarni tushuntiradi. Bu eng samarali mashq turi — chunki hamma narsa real sharoitda bajariladi."])],})

TOPICS.append({"num":10,"title":"Basketbol o'yini qoidasiga asosan ikki tomonga o'yin; musobaqalarda hakamlik qilish","reja":["Basketbol qoidalari asosida o'yin.","Ikki tomonga o'yin tashkil etish.","Hakamlik asoslari va signallar.","Musobaqani boshqarish va protokol yuritish."],"sections":[("Basketbol qoidalari asosida o'yin",["Basketbol qoidalari FIBA tomonidan belgilangan: 4 davr har biri 10 daqiqa, 24 soniya hujum vaqti, 8 soniya ichida to'pni raqib yarmiga o'tkazish, 5 soniya aut va jarima, 3 soniya raqib zonasida turish chegarasi. Bu qoidalar o'yin dinamikasini ta'minlaydi.","Qoidabuzarliklar: shaxsiy foul (jismoniy kontakt), texnik foul (sportga loyiq bo'lmagan xulq), flagrant foul (qo'pol buzilish). 5 ta shaxsiy foul — o'yinchi chiqariladi. Jamoaviy foullar 4 tadan oshsa — har bir keyingi foulda raqibga jarima tashlashi beriladi.","O'yin boshlanishi: markaziy doirada to'p tepaga otiladi (jump ball). Keyingi davrlarda possession arrow (navbat strelkasi) orqali boshlanadi. Tenglik bo'lsa — qo'shimcha 5 daqiqa (overtime). Bu qoidalarni bilish o'yinda to'g'ri harakat qilish uchun shart."]),("Ikki tomonga o'yin tashkil etish",["Ikki tomonga o'yin — mashg'ulotning eng muhim qismi. U real musobaqa sharoitlarini yaratadi va barcha texnik-taktik elementlarni amalda qo'llash imkonini beradi. Guruh ikkiga bo'linadi va to'liq qoidalar asosida o'ynaydi.","Tashkil etish: jamoalarni kuchiga qarab teng taqsimlash, vaqtni belgilash (2x10 yoki 4x5 daqiqa), hakamlik qilish (murabbiy yoki navbatma-navbat talabalar). Maxsus shartlar ham qo'yilishi mumkin: faqat 3 ochkolik, faqat zone himoya va boshqalar.","O'yindan keyin tahlil: murabbiy xatolarni ko'rsatadi, yaxshi momentlarni ta'kidlaydi, individual va jamoaviy ko'rsatmalar beradi. Video yozib olinsa — eng samarali tahlil. Bu talabalarni real musobaqalarga tayyorlaydi."]),("Hakamlik asoslari va signallar",["Basketbolda 2-3 hakam ishlaydi: bosh hakam (referee) va yordamchi hakamlar (umpires). Ular maydonda pozitsiyalarni taqsimlaydi va qoidabuzarliklarni kuzatadi. Har bir hakam o'z zonasiga mas'ul.","Hakam signallari: foul (musht bilan yuqoriga), o'yin to'xtashi (kaft ochiq yuqoriga), aut (yo'nalish ko'rsatish), time-out (T shakli), 2 ochko (barmoqlar ko'rsatish), 3 ochko (uch barmoq). Bu signallarni bilish talabalar uchun ham muhim.","Hakamlik qilishni o'rganish: qoidalarni mukammal bilish, tez qaror qabul qilish, xolis va adolatli bo'lish, fizik tayyorgarlik (maydonda harakatlanish), stressga chidamlilik. Talabalar o'quv musobaqalarida hakamlik qilib tajriba orttiradilar."]),("Musobaqani boshqarish va protokol yuritish",["Musobaqani boshqarish — tashkiliy va texnik jarayon: jadval tuzish, jamoalarni ro'yxatga olish, maydon va jihozlarni tayyorlash, hakamlarni tayinlash, oraliq va yakuniy natijalarni e'lon qilish.","Protokol yuritish: to'p hisoblash jadvali (scoring sheet), o'yinchilar ro'yxati, foullar qaydnomasi, vaqt nazorati, almashinishlar qaydnomasi. Hozirda elektron protokollar keng qo'llaniladi.","Talabalar musobaqalari uchun oddiy turnir formatlari: round-robin (har bir jamoa har biri bilan o'ynaydi), single-elimination (yutqazgan chiqadi), double-elimination (ikkita yutqazgandan keyin chiqadi). Talabalar nafaqat o'ynash, balki tashkil etish va hakamlik qilishni ham o'rganadilar."])],})

TOPICS.append({"num":11,"title":"Voleybol. Juftlikda to'pni, to'r ustidan yuqoridan va pastdan bir-biriga uzatishlar","reja":["Voleybolda uzatish texnikasi asoslari.","Yuqoridan uzatish (ustki peredacha).","Pastdan uzatish (pastki peredacha, manchette).","Juftlikda to'r ustidan uzatish mashqlari."],"sections":[("Voleybolda uzatish texnikasi asoslari",["Voleybolda uzatish (peredacha) — eng muhim texnik element. U o'yin qurilishining asosi: to'p qabul qilish, uzatuvchiga uzatish va hujumchiga tayyorlash — bularning barchasi uzatish texnikasiga asoslanadi. Yaxshi uzatishsiz samarali hujum bo'lmaydi.","Uzatish ikki asosiy turga bo'linadi: yuqoridan (barmoq uchlari bilan — overhand pass) va pastdan (bilak bilan — underhand pass, manchette). Har ikkalasi ham turli vaziyatlarda qo'llaniladi va mukammal egallanishi kerak.","To'g'ri uzatishning belgilari: aniqlik (kerakli joyga tushishi), yumshoqlik (to'p harakati silliq), balandlik (hujumchi uchun qulay), barqarorlik (har safar bir xil sifatda). Bu sifatlar ko'p mashq orqali erishiladi."]),("Yuqoridan uzatish (ustki peredacha)",["Yuqoridan uzatish texnikasi: oyoqlar yelka kengligida, tizzalar biroz bukilgan, qo'llar yuqorida — peshona oldida — barmoqlar yoyilgan 'choynaksimon' shaklda. To'p barmoq uchlari bilan tegadi va bilak-tirsak-yelka harakati bilan yo'naltiriladi.","Qo'llarning holati: barmoqlar yoyilgan, bosh va ko'rsatkich barmoqlar asosiy kuchni beradi, kaftlar biroz ichkariga burilgan. To'p kelayotganda — tizzalar egiladi (energiya yig'ish), keyin oyoqlar, gavda va qo'llar bir vaqtda ishlab to'pni yo'naltiradi. Bu yaxlit harakat.","Xatolar va ularni tuzatish: to'pni kaft bilan urish (barmoq uchi bilan bo'lishi kerak), oyoqlarni ishlatmaslik (faqat qo'l bilan — kuch yetishmaydi), noto'g'ri pozitsiya (to'p yonga ketadi). Har bir xato alohida mashqlar bilan tuzatiladi."]),("Pastdan uzatish (pastki peredacha, manchette)",["Pastki uzatish (manchette) texnikasi: qo'llar birlashtirilgan — bir kaftni ikkinchisiga qo'yib, bosh barmoqlar parallel; tirsaklar to'g'ri, bilaklar — to'pni uriladigan yuzasi; oyoqlar keng, tizzalar bukilgan, gavda past va oldinga egilgan.","To'p bilakning pastki qismiga (bilak suyagi ustiga) tegadi. Kuch oyoqlardan keladi — qo'llar ko'proq yo'naltiruvchi. Qo'llarni tepaga silkitmaslik kerak — bu to'pni nazoratdan chiqaradi. Buning o'rniga oyoqlar ishlatiladi va to'p platformadan kerakli burchakda qaytadi.","Pastki uzatish asosan qabul qilishda (receive) va himoyada ishlatiladi: podacha qabul qilishda, hujum urishi himoyasida (dig) va past kelgan to'plarni ko'tarishda. Bu element voleybolda eng ko'p ishlatiladigan texnika hisoblanadi."]),("Juftlikda to'r ustidan uzatish mashqlari",["Boshlang'ich mashq: juftlikda 3m masofada bir-biriga yuqoridan uzatish (to'r yo'q). Maqsad — texnikani to'g'ri bajarish, aniqlik va barqarorlik. 20-30 marta uzluksiz uzatish — maqsad.","To'r ustidan mashq: ikki o'yinchi to'rning ikki tomonida turadi, to'pni yuqoridan va pastdan navbatma-navbat to'r ustidan uzatadi. Avval baland va sekin, keyin pastroq va tezroq. Maqsad — to'pni nazoratda saqlash va aniq uzatish.","Murakkab variatsiyalar: harakat qilib uzatish (o'ng-chapga surilib), sakrab uzatish (jump set), orqaga uzatish (back set), uzun uzatish (to'rning bir uchidan ikkinchi uchiga). Bu mashqlar o'yin vaziyatlariga yaqinlashtiradi va moslashuvchanlikni rivojlantiradi."])],})

TOPICS.append({"num":12,"title":"Voleybolda harakat qilish texnikasining asosiy elementlari kombinatsiyalarini takomillashtirish","reja":["Voleybol texnikasi elementlarining birikmalari.","Qabul-uzatish-hujum kombinatsiyasi.","Himoya va kontr-hujum.","Mashg'ulotda kombinatsiyalarni mashq qilish."],"sections":[("Voleybol texnikasi elementlarining birikmalari",["Voleybolda alohida texnik elementlarni egallash yetarli emas — ularni o'yin sharoitida ketma-ket va tez bajarish kerak. Kombinatsiya — ikki yoki undan ortiq elementning uzluksiz birikmasidir. Masalan: qabul qilish va darhol uzatish, uzatish va darhol hujum.","Asosiy kombinatsiyalar: serve-receive + set (qabul va uzatish), set + spike (uzatish va hujum), dig + set + spike (himoya + uzatish + hujum), block + transition (blok va kontr-hujum). Har bir kombinatsiya alohida mashq qilinadi.","Kombinatsiyaning sifati — vaqt sinxronizatsiyasi: har bir o'yinchi to'g'ri vaqtda to'g'ri joyda bo'lishi kerak. Bu jamoaviy mashq va o'zaro tushunishni talab qiladi. Ko'p mashq qilish orqali avtomatizm hosil bo'ladi."]),("Qabul-uzatish-hujum kombinatsiyasi",["Bu voleybolning asosiy hujum zanjiri: 1) libero yoki orqa o'yinchi podachani qabul qiladi (manchette), 2) uzatuvchi (setter) to'pni oladi va hujumchiga uzatadi (barmoq uchlari bilan), 3) hujumchi sakrab to'pni kuchli uradi (spike). Bu 3 tegishish ichida bajariladi.","Har bir bosqich muhim: qabul — aniq uzatuvchi ga borishi kerak; uzatish — hujumchiga qulay balandlik va joy ga; hujum — kuchli va to'g'ri yo'nalishga. Bir bosqichdagi xato butun zanjirni buzadi.","Mashq usuli: avval juftlikda (qabul-uzatish), keyin uchtada (qabul-uzatish-hujum), keyin to'liq jamoa bilan (6 kishilik). Avval raqibsiz, keyin bloklash bilan. Bosqichma-bosqich murakkablashtirish kombinatsiyani mustahkamlaydi."]),("Himoya va kontr-hujum",["Himoya kombinatsiyasi: blok (to'rda 1-3 o'yinchi) + maydon himoyasi (orqadagi o'yinchilar). Blokchilar to'rda raqib hujumini to'xtatishga, orqadagi o'yinchilar esa blokdan o'tgan to'pni ko'tarishga harakat qiladi.","Transition (o'tish) — himoyadan hujumga tez o'tish: to'p qabul qilingandan keyin jamoa darhol hujum tashkil qiladi. Bu tez va muvofiqlashtirilgan harakat talab qiladi. Yaxshi transition samarali kontr-hujumga olib keladi.","Mashq usuli: 6v6 o'yinda murabbiy turli vaziyatlarni yaratadi (to'pni turli joyga otadi) va jamoa himoya + transition mashq qiladi. Video tahlil orqali xatolar aniqlanadi. Bu mashqlar jamoaviy hamkorlikni mustahkamlaydi."]),("Mashg'ulotda kombinatsiyalarni mashq qilish",["Mashg'ulot tuzilmasi: 1) alohida elementlar mashqi (20 daqiqa), 2) juftlikda va uchtada kombinatsiyalar (20 daqiqa), 3) jamoaviy mashq — 6v6 sharoitida (20 daqiqa), 4) maxsus vaziyatlar mashqi (10 daqiqa). Bu tuzilma oddiydan murakkabga tamoyiliga asoslanadi.","Drill mashqlari: 'oynash' (wash drill — har ikki tomon hujum qiladi, kim oldin 3 ochko olsa yutadi), 'podacha va qabul' (serve-receive drill), '6v6 shartli o'yin' (masalan, faqat tez hujum). Bu drilllar real o'yinga yaqin sharoitlar yaratadi.","Natijalarni baholash: murabbiy kombinatsiya muvaffaqiyat foizini kuzatadi (masalan: 10 ta qabul-uzatish-hujumdan nechtasi gol bo'ldi). Bu statistik ko'rsatkichlar jamoaning taraqqiyotini ko'rsatadi va mashg'ulot dasturini tuzatishga yordam beradi."])],})

TOPICS.append({"num":13,"title":"Qo'l to'pi. To'p bilan ishlash texnikasini mukammallashtirish","reja":["Qo'l to'pi (gandbol) haqida umumiy ma'lumot.","To'pni ushlash va uzatish texnikasi.","To'pni urish va darvozaga otish.","To'p bilan ishlash mashqlari."],"sections":[("Qo'l to'pi (gandbol) haqida umumiy ma'lumot",["Qo'l to'pi (gandbol, handball) — 7 kishilik jamoalar o'rtasida o'ynaladigan sport o'yini. Maqsad — to'pni raqib darvozasiga qo'l bilan otib kiritish. Maydon 40x20 metr, darvoza 3x2 metr. O'yin ikki davr (har biri 30 daqiqa). Olimpiya dasturida 1972-yildan beri.","Gandbol intensiv va dinamik o'yin: jismoniy kuch, tezlik, chidamlilik va texnik mahoratni talab qiladi. O'yinchilar tez harakatlanadi, to'pni uzatib va qabul qilib, darvozaga hujum qiladi. Himoyachilar raqibni to'xtatishga harakat qiladi.","O'zbekistonda qo'l to'pi rivojlanmoqda: maktab va universitet jamoalari faoliyat yuritadi. Bu sport turi talabalar orasida mashhur, chunki u jismoniy rivojlanish va jamoaviy hamkorlik uchun juda foydali."]),("To'pni ushlash va uzatish texnikasi",["To'pni ushlash: bir qo'l bilan ushlash (katta qo'l kerak) yoki ikki qo'l bilan. Barmoqlar to'p atrofida yoyilgan, kaft to'pga yopishgan. To'p xavfsiz va ishonchli ushlangan bo'lishi kerak — yo'qotmaslik uchun.","Uzatish turlari: yelka ustidan (eng keng tarqalgan — kuchli va uzoq), ko'krakdan (qisqa masofa), polga urilib (raqib qo'llari orasidan), orqa tomondan (kutilmagan). Har bir uzatish aniq va tez bo'lishi kerak.","Qabul qilish: ikkala qo'l bilan (ko'krak balandligida), bir qo'l bilan (yuqorida yoki pastda), sakrab qabul qilish. Qabul qilishda qo'llar to'pga yaqinlashib, yumshoq tutadi (to'pni 'so'radi'). Ko'zlar doim to'pda bo'lishi shart."]),("To'pni urish va darvozaga otish",["Darvozaga otish — gandbolning asosiy hujum elementi. Otish turlari: yelka ustidan (standing throw — eng kuchli), sakrab otish (jump shot — eng ko'p ishlatiladigan), tushib otish (falling shot — past burchakka), orqa tomonga otish (spin shot — kutilmagan).","Otish texnikasi (sakrab otish): yugurib kelish — oxirgi 3 qadam — sakrash (bir oyoqdan) — qo'l orqaga tortiladi — gavda buriladi — qo'l kuch bilan oldinga harakatlanib to'pni otadi. Bilak 'qamchi' shaklida ishlaydi — bu tezlik va kuch beradi.","Otish aniqligi mashq bilan rivojlanadi: turli burchaklardan, turli masofadan, turli holatda (sakrab, tushib, yugurish ichida). Darvoza burchaklariga nishon qo'yib otish — aniqlikni oshiradi. Har mashg'ulotda 50-100 ta otish bajariladi."]),("To'p bilan ishlash mashqlari",["Uzatish mashqlari: juftlikda turli masofada (3m, 5m, 8m), turli turlarda (yelka ustidan, ko'krakdan, polga), harakatda uzatish (yugurib kelib uzatish va qabul qilish). Aniqlik va tezlik maqsad qilinadi.","Driblling mashqlari: to'pni bir qo'l bilan yerga urib harakatlanish (basketboldagidek, lekin gandbol to'pi bilan), to'p bilan 3 qadam qilish (qoida — 3 qadamdan keyin uzatish yoki otish kerak), raqibdan qochib harakatlanish.","Kompleks mashqlar: uzatish + otish (sherikdan qabul qilib darhol darvozaga), driblling + otish (3 qadam + sakrab otish), kontr-hujum mashqi (tez hujum — 2v1, 3v2). Bu mashqlar o'yindagi real vaziyatlarni tayyorlaydi."])],})

TOPICS.append({"num":14,"title":"Futbol texnika va taktika usullarini o'rgatish","reja":["Futbol texnikasini o'rgatish metodikasi.","Asosiy texnik elementlarni bosqichma-bosqich o'rgatish.","Taktikani o'rgatish usullari.","Mashg'ulotda texnika va taktikani birlashtirish."],"sections":[("Futbol texnikasini o'rgatish metodikasi",["Futbol texnikasini o'rgatish metodikasi pedagogik tamoyillarga asoslanadi: ko'rgazmalilik (ko'rsatish), onglilik (tushuntirish), izchillik (oddiydan murakkabga), takrorlash (mustahkamlash) va individual yondashuv (har bir talabaning darajasiga moslashtirish).","O'rgatish bosqichlari: 1) tanishish (ko'rsatish va tushuntirish), 2) o'rganish (takrorlash, xatolarni tuzatish), 3) mustahkamlash (turli sharoitlarda mashq), 4) takomillashtirish (o'yinda qo'llash). Har bir bosqich o'z vaqtida va tartibda o'tiladi.","O'qituvchining vazifalari: texnikani to'g'ri ko'rsatish (namoyish), aniq tushuntirish, xatolarni erta aniqlash va tuzatish, individual yondashuv (kuchli va zaif talabalar uchun alohida mashqlar), motivatsiya berish va ijobiy muhit yaratish."]),("Asosiy texnik elementlarni bosqichma-bosqich o'rgatish",["To'pni boshqarish (dribbling): avval turgan joyda to'pni boshqarish, keyin sekin yurish bilan, keyin yugurish bilan, keyin konuslar orasida, keyin raqibga qarshi. Har bir bosqichda tezlik va murakkablik oshadi.","Uzatish (passing): avval juftlikda turgan joyda (5m masofada), keyin uzoqroq masofada, keyin harakatda, keyin raqib bosimi ostida. Oyoq ichidan uzatish — birinchi o'rganiladigan element (eng asosiy va ko'p ishlatiladigan).","Urish (shooting): avval turgan to'pni darvozaga urish, keyin harakatdagi to'pni, keyin yugurish ichida, keyin raqib himoyasi ostida. Oyoq ichi bilan (aniqlik) va son ichi bilan (kuch) urish — ikki asosiy texnika."]),("Taktikani o'rgatish usullari",["Taktikani o'rgatish individual va jamoaviy bo'ladi. Individual: raqibni chetlab o'tish, bo'sh joyga chiqish, himoyada pozitsiya saqlash. Jamoaviy: hujumda kombinatsiyalar, himoyada hamkorlik, o'tishlar (transition).","O'rgatish usullari: 1) taktik doskada (marker yoki magnitlar bilan sxema chizish), 2) video tahlil (professional o'yinlardan misollar), 3) amaliy mashq (maydonda taktik vaziyatlarni yaratish), 4) o'quv o'yinida taktikani qo'llash.","Small-sided games (kichik maydonli o'yinlar — 3v3, 4v4, 5v5) — taktikani o'rgatishning eng samarali usuli. Kichik maydonda har bir o'yinchi ko'proq qaror qabul qiladi, ko'proq to'pga tegadi va taktik vaziyatlar tez-tez takrorlanadi."]),("Mashg'ulotda texnika va taktikani birlashtirish",["Zamonaviy mashg'ulot tuzilmasi: texnika va taktika alohida emas, birga o'rgatiladi. Masalan: uzatish texnikasini mashq qilishda — raqib bosimi ostida uzatish (taktik element qo'shiladi). Bu real o'yinga yaqinroq.","Mashg'ulot rejasi: 1) qizdiruv (15 daqiqa — to'p bilan o'yinlar), 2) texnik mashqlar (20 daqiqa — asosiy element), 3) taktik mashqlar (20 daqiqa — kichik o'yinlar), 4) o'quv o'yini (20 daqiqa — to'liq o'yin), 5) tiklanish (10 daqiqa). Bu tuzilma oddiydan murakkabga ketadi.","Mashg'ulot samaradorligini oshirish: har bir mashqda aniq maqsad bo'lishi, talabalar faol bo'lishi (kutish vaqti kam), mashqlar o'yin sharoitlariga yaqin bo'lishi, murabbiy doimiy aloqada bo'lishi (feedback berishi). Sifatli 90 daqiqa — uzun lekin samarasiz 2 soatdan yaxshiroq."])],})

TOPICS.append({"num":15,"title":"Futbol texnika va taktika usullarini o'rgatish (davomi)","reja":["Hujum taktikasini o'rgatish.","Himoya taktikasini o'rgatish.","Standart vaziyatlar mashqlari.","Jamoaviy o'yin mashqlari."],"sections":[("Hujum taktikasini o'rgatish",["Hujum taktikasini o'rgatishda asosiy tushunchalar: kenglik (maydanning eniga foydalanish), chuqurlik (oldinga harakat), harakatchanlik (pozitsiyani o'zgartirish) va kombinatsiyalar (sheriklar bilan hamkorlik).","Amaliy mashqlar: 2v1 vaziyatlar (ikki hujumchi bir himoyachiga qarshi — o'tib ketish), 3v2 vaziyatlar, kenglikka o'ynash (switch play), bo'sh joyga chiqish (overlapping run), one-two kombinatsiyasi (wall pass).","O'rgatish tartibi: avval raqibsiz harakatlar (pozitsiyalarni tushunish), keyin passiv raqib (qarshilik ko'rsatmaydi), keyin aktiv raqib (to'liq himoya). Bu bosqichma-bosqich tizim talabaning taktik fikrlashini rivojlantiradi."]),("Himoya taktikasini o'rgatish",["Himoya taktikasining asoslari: kompaktlik (jamoaning bir-biriga yaqin bo'lishi), chuqurlik (bir nechta himoya liniyasi), kechiktirish (raqibning hujumini sekinlashtirish) va balans (yon tomonlar himoyasi).","Individual himoya: raqibga yaqin turish, gavda pozitsiyasi (yon tomonga burilib, darvozaga qarab), raqibni yon tomonga yo'naltirish. Jamoaviy himoya: zonal (hududni himoya qilish), man-to-man (shaxsiy kuzatish), pressing (yuqorida bosim).","Mashqlar: 1v1 himoya (raqibni to'xtatish), 2v2 (sherik bilan himoya hamkorligi), 4v4 (kichik maydonli o'yin — himoya urg'usi bilan), 11v11 (to'liq o'yinda himoya tizimini mashq qilish)."]),("Standart vaziyatlar mashqlari",["Standart vaziyatlar (set pieces): erkin urish (free kick), burchak urishi (corner kick), penalti, aut, darvozabondan boshlash. Bu vaziyatlar gollarning 30-40 foizini tashkil etadi — shuning uchun alohida mashq qilinadi.","Erkin urish mashqlari: devor ustidan eguvchi urish, devor yonidan urish, qisqa kombinatsiya (raqibni aldash). Burchak urishi: old ustun ga, orqaga, qisqa burchak (short corner). Har bir vaziyat uchun signal va harakat belgilangan.","Himoyada standart vaziyatlarga qarshi: devor qurish (erkin urishda), burchak urishi himoyasi (zonali yoki shaxsiy), penalti himoyasi (darvozabon mashqi). Bu vaziyatlarni muntazam mashq qilish kerak — ular o'yinning muhim qismidir."]),("Jamoaviy o'yin mashqlari",["Jamoaviy o'yin — barcha individual va guruhli elementlarning yaxlit tizimga birlashishi. 11v11 o'quv o'yinida butun jamoa birgalikda harakat qiladi: hujum, himoya, o'tish (transition).","Mashg'ulotda jamoaviy o'yin: murabbiy formatsiyani (4-3-3, 4-4-2) belgilaydi, har bir o'yinchining roli va vazifasini tushuntiradi, taktik signallar o'rgatadi va o'yin davomida ko'rsatmalar beradi.","O'yindan keyin tahlil: jamoaviy harakat sifati baholanadi — hujumda va himoyada muvofiqlik, o'tishlar tezligi, standart vaziyatlar bajarilishi. Video tahlil eng samarali — jamoa xatolarni ko'radi va tuzatish ustida ishlaydi."])],})

TOPICS.append({"num":16,"title":"Futbol qoidasiga ko'ra ikki tomonga o'yin","reja":["Futbol qoidalari asosida o'yin o'tkazish.","O'quv o'yinini tashkil etish.","O'yin davomida texnika va taktikani qo'llash.","O'yin tahlili va xulosalar."],"sections":[("Futbol qoidalari asosida o'yin o'tkazish",["Ikki tomonga o'yin (two-sided game) — futbol mashg'ulotining yakuniy qismi bo'lib, bunda ikki jamoa to'liq qoidalar asosida o'ynaydi. Bu o'rganilgan texnika va taktikani real musobaqa sharoitida qo'llash imkonini beradi.","To'liq qoidalar qo'llaniladi: ofsayd, foullar, autlar, kornerlar, erkin urishlar. O'yin 11v11 (to'liq) yoki kichikroq formatda (7v7, 9v9) o'tkazilishi mumkin — talabalar soniga qarab.","Murabbiy hakamlik qiladi yoki talabalar o'rtasidan hakam tayinlanadi. Bu talabalarning nafaqat o'ynash, balki qoidalarni bilish va hakamlik qilish ko'nikmalarini ham rivojlantiradi."]),("O'quv o'yinini tashkil etish",["Tashkil etish: jamoalarni teng kuchli taqsimlash, rang farqlash (marker vest), maydonni tayyorlash, vaqtni belgilash (2x15 yoki 2x20 daqiqa), darvozalarni o'rnatish. Talabalar soni ko'p bo'lsa — bir nechta maydon yoki almashinish tizimi.","Maxsus shartlar qo'yish mumkin: 'faqat 2 tegishish' (tez o'yin uchun), 'faqat birinchi tegishishdan uzatish' (one-touch), 'qanot orqali hujum' (kenglik uchun). Bu shartlar muayyan texnik yoki taktik elementni mashq qilishga qaratilgan.","Murabbiy o'yin davomida: 1) kuzatadi va qayd qiladi (xatolar, yaxshi momentlar), 2) kerak bo'lganda to'xtatib tushuntiradi (coaching moment), 3) rag'batlantiradi va motivatsiya beradi, 4) vaqtni boshqaradi."]),("O'yin davomida texnika va taktikani qo'llash",["O'quv o'yinning asosiy maqsadi — mashg'ulotda o'rganilgan elementlarni real sharoitda qo'llash. Masalan, agar mashg'ulotda uzatish mashq qilingan bo'lsa — o'yinda uzatish sifatiga alohida e'tibor beriladi.","Real o'yinda texnikaning sifati pasayadi (raqib bosimi, charchash, stress tufayli) — bu tabiiy. Lekin har bir o'yin bilan texnika real sharoitlarga moslashadi. Shuning uchun o'quv o'yini mashg'ulotning eng muhim qismidir — u bilimni ko'nikmaga aylantiradi.","Taktikani o'yinda qo'llash: formatsiyani saqlash, raqibga moslashish, tez o'tish (himoyadan hujumga), jamoaviy harakatlar. Murabbiy taktik ko'rsatmalarni o'yin davomida beradi va talabalarning taktik fikrlashini rivojlantiradi."]),("O'yin tahlili va xulosalar",["O'yindan keyin tahlil — o'qitishning muhim qismi. Murabbiy asosiy nuqtalarni muhokama qiladi: nima yaxshi qilindi (ta'kidlash), nima xato qilindi (tuzatish), keyingi mashg'ulotda nimaga e'tibor berish kerak.","Talabalarning fikri ham muhim: ular o'yin haqida o'z mulohazalarini bildiradilar, qiyinchiliklarni aytadilar va takliflar beradilar. Bu refleksiya — mustaqil fikrlash va o'z-o'zini baholash ko'nikmasini rivojlantiradi.","Tahlil natijalari keyingi mashg'ulot rejasiga kiritiladi: aniqlangan zaif tomonlar bo'yicha qo'shimcha mashqlar rejalanadi. Bu uzluksiz takomillashtirish tsikli — mashq, o'yin, tahlil, qayta mashq — sport mahoratini barqaror oshirib boradi."])],})

TOPICS.append({"num":17,"title":"Futbol qoidasiga ko'ra ikki tomonga o'yin (davomi)","reja":["Turli formatdagi futbol o'yinlari.","Kichik maydondagi o'yinlarning afzalliklari.","Musobaqa muhitini yaratish.","Individual va jamoaviy rivojlanishni baholash."],"sections":[("Turli formatdagi futbol o'yinlari",["Futbol turli formatlarda o'ynalishi mumkin: 5v5 (futsal turi), 7v7 (yoshlar uchun), 9v9 (o'rta yosh), 11v11 (standart). Har bir format o'z maydon o'lchami, darvoza kattaligi va o'yin davomiyligiga ega.","Kichik formatlar (5v5, 7v7) mashg'ulotda samarali: har bir o'yinchi ko'proq to'pga tegadi, ko'proq qaror qabul qiladi, intensivlik yuqori va texnik-taktik rivojlanish tezroq kechadi.","Yana turli variantlar: futsal (yopiq zalda, 5v5, kichik to'p), plyaj futboli (qumda, 5v5), mini-futbol. Har biri o'ziga xos texnika va taktikani talab qiladi va asosiy futbol mahoratini rivojlantirishga hissa qo'shadi."]),("Kichik maydondagi o'yinlarning afzalliklari",["Kichik maydon (small-sided games — SSG) afzalliklari: 1) to'pga tegish soni 3-5 baravar ko'payadi, 2) qarorlar tezroq qabul qilinadi (vaqt chegarasi), 3) intensivlik yuqori (ko'proq sprint), 4) jismoniy va texnik tomonlar birga rivojlanadi.","Tadqiqotlar ko'rsatadiki: SSG jismoniy tayyorgarlik uchun oddiy yugurishdan samarali — chunki u o'yinga xos harakatlarni o'z ichiga oladi (stop-start, tez yo'nalish o'zgartirish, sprint). Shu bilan birga texnika va taktika ham mashq bo'ladi.","SSG formatlarni o'zgartirish orqali turli maqsadlarga erishish mumkin: kichik maydon (1v1, 2v2) — individual texnikaga; o'rta (4v4, 5v5) — guruhli taktikaga; kattaroq (7v7, 9v9) — jamoaviy taktikaga yo'naltirilgan."]),("Musobaqa muhitini yaratish",["O'quv o'yinda musobaqa muhitini yaratish muhim: ochko hisoblash, vaqt chegarasi, g'olibni aniqlash. Bu talabalarni motivatsiyalaydi va real musobaqadagi bosimga ko'niktiradi.","Turnir formatlarini qo'llash: sinf ichida mini-turnirlar (round-robin), 'king of the hill' (yutgan jamoa qoladi, yutqazgan o'zgaradi), playoff (chiqarish tizimi). Bu formatlar qiziqish va raqobat muhitini yaratadi.","Musobaqa muhitida talaba haqiqiy stress va bosimni his qiladi: tezroq qaror qabul qilishi kerak, xato qilishdan qo'rqadi, jamoa uchun javobgarlik his qiladi. Bu tajribalar haqiqiy musobaqalarga tayyorlaydi."]),("Individual va jamoaviy rivojlanishni baholash",["Individual baholash: texnika sifati (driblling, uzatish, urish), taktik fikrlash (qaror qabul qilish sifati), jismoniy ko'rsatkichlar (sprint, chidamlilik) va ruhiy sifatlar (liderlik, bardoshlilik). Har bir talaba uchun individual profil tuziladi.","Jamoaviy baholash: hujum samaradorligi (gol urishlar soni), himoya barqarorligi (kiritilgan gollar), to'p egaligi (possession foizi), uzatish aniqligi va jamoaviy muvofiqlik. Bu ko'rsatkichlar jamoaning darajasini ko'rsatadi.","Rivojlanish dinamikasi — eng muhim ko'rsatkich: talabaning o'zining oldingi natijalariga nisbatan o'sishi. Har bir mashg'ulot va o'yin natijalari qayd qilinadi va dinamika kuzatiladi. Bu talabaga motivatsiya beradi va murabbiyga dasturni tuzatishda yordam beradi."])],})

TOPICS.append({"num":18,"title":"Futbol o'yinida hakamlik qilish","reja":["Futbol hakamligining asoslari.","Hakam signallari va qarorlari.","Maydondagi hakamlar pozitsiyasi.","Amaliy hakamlik mashqi."],"sections":[("Futbol hakamligining asoslari",["Futbol hakami — o'yinda qoidalarning bajarilishini nazorat qiluvchi rasmiy shaxs. U o'yin boshlanishidan tugashigacha barcha qarorlarni qabul qiladi. Hakam xolis, adolatli va professional bo'lishi shart. Uning qarorlari yakuniy.","Hakamlik tarkibi: bosh hakam (maydonda), ikki yordamchi hakam (liniya bo'ylab — aut, ofsayd), to'rtinchi hakam (almashinishlar, qo'shimcha vaqt). Zamonaviy futbolda VAR (Video Assistant Referee) ham mavjud (professional darajada).","Hakam uchun zarur sifatlar: qoidalarni mukammal bilish, jismoniy tayyorgarlik (90 daqiqa maydon bo'ylab yugurish — 10-12 km), tez qaror qabul qilish, stressga chidamlilik, o'z-o'zini nazorat qilish va muloqot mahorati."]),("Hakam signallari va qarorlari",["Asosiy signallar: still (hushtak — o'yin to'xtatish/boshlash), erkin urish yo'nalishi (qo'l ko'tarish), sariq kartochka (ogohlantirish), qizil kartochka (chetlatish), penalti (nuqtani ko'rsatish), gol (markaz doiraga ishora), burchak (bayroq tomonga qo'l).","Yordamchi hakam signallari: bayroqni ko'tarish (ofsayd, aut, foul), bayroq yo'nalishi (qaysi jamoa uchun). Bayroq tizimlari standartlashtirilgan — har bir signal aniq ma'no beradi.","Qaror qabul qilish: hakam vaziyatni ko'radi, qoidaga mosligini aniqlaydi, qaror qabul qiladi va signal beradi — bularning hammasi 1-2 soniya ichida. Mushkul vaziyatlarda (penalti? foul? ofsayd?) hakam o'z tajribasiga va pozitsiyasiga tayanadi."]),("Maydondagi hakamlar pozitsiyasi",["Bosh hakam maydon bo'ylab diagonal tizimda harakatlanadi: bir burchakdan qarama-qarshi burchakka. Bu eng ko'p vaziyatlarni yaqindan ko'rish imkonini beradi. Hakam doimo to'pga yaqin bo'lishga, lekin o'yinga xalaqit bermaslikka harakat qiladi.","Yordamchi hakamlar yon chiziq bo'ylab harakatlanadi: ular oxirgi himoyachi chizig'ida turadi (ofsayd aniqlash uchun). Ular faqat bosh hakam ko'rmagan vaziyatlarni bildiradi — lekin yakuniy qaror bosh hakamda.","Jismoniy tayyorgarlik: hakam o'yin davomida 10-12 km yuguradi (turli intensivlikda — sprint, o'rta va sekin tezlikda). Shuning uchun hakamlar ham sportchilar kabi mashq qiladilar: interval yugurish, sprint, epchillik mashqlari."]),("Amaliy hakamlik mashqi",["Talabalar uchun hakamlik mashqi: avval qoidalarni o'rganish (nazariy tayyorgarlik), keyin o'quv o'yinda yordamchi sifatida hakamlik (kuzatish), keyin bosh hakam sifatida hakamlik (amaliy). Bosqichma-bosqich murakkablik oshadi.","Mashq usullari: video darslar (professional hakamlar ishini ko'rish), syujetli mashqlar (muayyan vaziyatni hal qilish), o'quv musobaqalarida hakamlik (real tajriba), hakam bilan seminar (tajribali hakamdan maslahat olish).","Hakamlik qilish talabalarga qoidalarni chuqurroq tushunishga, sportga hurmatni oshirishga va qaror qabul qilish mahoratini rivojlantirishga yordam beradi. Bu hayotda ham foydali ko'nikma — adolatli va xolis qaror qabul qilish."])],})

TOPICS.append({"num":19,"title":"Kurash usullari","reja":["Kurash sport turi haqida umumiy ma'lumot.","Kurashda asosiy texnik usullar.","Kurash taktikasi.","Kurash mashqlari va xavfsizlik."],"sections":[("Kurash sport turi haqida umumiy ma'lumot",["Kurash — O'zbekistonning milliy sport turi bo'lib, uning tarixi 3500 yildan ortiq. 1998-yilda Xalqaro kurash assotsiatsiyasi (IKA) tashkil topgan. Kurash o'zbek tilida 'olishuv' degan ma'noni anglatadi. U halol va adolatli olishuvning timsolidir.","Kurash qoidalari: ikki polvon maxsus to'n (yashil va ko'k) kiyib, gilam ustida bellashadi. Maqsad — raqibni chalagi yoki to'liq yiqitish. O'yin vaqti: kattalar uchun 4 daqiqa, yoshlar uchun 3 daqiqa. Vazn toifalari mavjud.","Kurash xalqaro miqyosda tan olingan: Osiyo o'yinlari dasturida, Jahon chempionatlari o'tkaziladi. O'zbekiston polvonlari doimo eng kuchlilar qatorida. Kurash 2022-yilda Olimpiya tan olingan sport turlariga kiritildi (Olimpiya dasturiga kiritilish jarayonida)."]),("Kurashda asosiy texnik usullar",["Kurashda ikki asosiy texnik guruh: yiqitishlar (tashlash) va to'siqlar (chalgitish). Yiqitish usullari: chala (yarim yiqitish — yon tomonga), xalol (to'liq yiqitish — orqaga), yonbosh (yon tomonga to'liq yiqitish).","Asosiy usullar: 1) orqa oyoqdan ilish (o'g'irish), 2) dast bilan tortib yiqitish, 3) budrash (oyoqni ilintirish), 4) ko'tarib yiqitish, 5) yon tomonga otish, 6) orqaga tortib otish. Har bir usulning o'z texnikasi va qo'llash sharoiti bor.","Kurashda qo'llar faqat raqibning to'ni (belidanig yuqori qismi) ni tutadi. Oyoq bilan urish, bo'g'ish, qo'l bukish taqiqlangan. Bu kurashni xavfsiz va halol sport turiga aylantiradi."]),("Kurash taktikasi",["Hujum taktikasi: raqibni doimiy bosim ostida saqlash, kutilmagan hujumlar, raqibning zaifligi (chap yoki o'ng tomonni aniqlash), hujumlarni kombinatsiyalash (bir usul sifatida, keyin tezda boshqasiga o'tish).","Himoya taktikasi: muvozanatni saqlash, gavdani to'g'ri tutish, raqib usulini oldindan sezish va qarshi harakat. Himoyadan hujumga o'tish — kontr-hujum (raqib hujum qilayotganda, uning energiyasini o'ziga qarshi ishlatish).","Taktik tayyorgarlik: raqibni o'rganish (kuchli va zaif tomonlari), o'z kuchli usullarini belgilash, musobaqa rejasini tuzish (birinchi daqiqada nima qilish, vaqt tugashiga yaqin nima qilish). Tajriba va mashq taktik mahoratni oshiradi."]),("Kurash mashqlari va xavfsizlik",["Maxsus mashqlar: rezinka bilan tortish (kuchni rivojlantirish), partner bilan o'yin mashqlari (reaksiya, tezlik), gilam ustida umbalov va tushish texnikasi (yiqilishda shikastlanmaslik), texnik usullarni qismlar bo'yicha mashq qilish.","Jismoniy tayyorgarlik: kuch (tortilish, otjimaniya, squat), chidamlilik (yugurish, intervalar), epchillik (koordinatsion mashqlar), egiluvchanlik (cho'zilish). Kurash uchun asosan kuch va chidamlilik muhim.","Xavfsizlik qoidalari: faqat gilam ustida (mat bilan), avval tushish texnikasini o'rganish (yiqilganda shikastlanmaslik), faqat murabbiy rahbarligida mashq qilish, eshitilmagan usullarni urinmaslik. Ehtiyotkorlik — kurashda sog'lom bo'lishning kafolati."])],})

TOPICS.append({"num":20,"title":"Shaxmat. Amaliy o'yinlar","reja":["Shaxmat o'yini va uning jismoniy tarbiyaga aloqasi.","Shaxmat asoslari va qoidalari.","Shaxmat taktikasi va strategiyasi.","Amaliy o'yinlar va turnir tashkil etish."],"sections":[("Shaxmat o'yini va uning jismoniy tarbiyaga aloqasi",["Shaxmat — aqliy sport turi bo'lib, unda ikki o'yinchi navbatma-navbat yurish qilib, raqib shohini mat qilishga intiladi. Shaxmat Xalqaro Olimpiya qo'mitasi tomonidan sport turi sifatida tan olingan, Jahon chempionatlari va Olimpiadalar o'tkaziladi.","Shaxmatning jismoniy tarbiya darslarida o'rni: u mantiqiy fikrlashni, diqqatni jamlashni, strategik rejalashtirishni va stressga chidamlilikni rivojlantiradi. Bu sifatlar har qanday sport turida ham zarur — shuning uchun shaxmat sportchining aqliy tayyorgarligini oshiradi.","Shaxmat 'fikr gimnastikasi' deb ham ataladi: uzun o'yin (3-5 soat) davomida o'yinchi doimiy intellektual kuchlanishda bo'ladi. Bu konsentratsiya va ruhiy chidamlilikni talab qiladi — shu jihatdan shaxmat jismoniy sport turlari bilan umumiy jihatga ega."]),("Shaxmat asoslari va qoidalari",["Shaxmat taxtasi 8x8 = 64 kataklarda (oq va qora) o'ynaladi. Har bir o'yinchida 16 dona figuralar bor: 1 shoh, 1 vazir (farzin), 2 fil (loy), 2 ot (asp), 2 rux (tura) va 8 piyoda (sarboz). Har bir figuraning o'z yurish qoidasi bor.","Figuralar yurishi: shoh — bir qadam har tomonga; vazir — to'g'ri va diagonal cheksiz; rux — to'g'ri cheksiz; fil — diagonal cheksiz; ot — 'L' shaklida (2+1); piyoda — oldinga 1 qadam (boshlang'ichda 2), diagonal bilan oladi.","Asosiy tushunchalar: shoh (shah — shohga tahdid), mat (shoh qochib qutula olmaydi — o'yin tugadi), pat (yurish navbatidagi o'yinchining qonuniy yurishi yo'q, lekin shohi shahda emas — durang), rokkirovka (shoh va ruxning maxsus birgalikdagi yurishi — himoya uchun)."]),("Shaxmat taktikasi va strategiyasi",["Shaxmat taktikasi — qisqa muddatli maqsadlarga erishish uchun figuralar kombinatsiyasi. Asosiy taktik usullar: vilka (fork — bir figura ikki nishonni tahdid qiladi), shtift (pin — orqadagi qimmatli figurani himoya qilib turilgan), skewer (teskari shtif), ochiq hujum (discovered attack).","Shaxmat strategiyasi — uzoq muddatli reja: markaz nazorati (markazdagi figuralar kuchli), figuralarni rivojlantirish (tezroq maydonga chiqarish), shoh xavfsizligi (rokkirovka), piyodalar strukturasi (zaif piyodalardan qochish) va endshpil texnikasi (yakuniy o'yinda g'alaba qozonish).","O'yin bosqichlari: debyut (dastlabki 10-15 yurish — figuralarni rivojlantirish), o'rta o'yin (middlegame — aktiv kurash, taktika), endshpil (kam figura bilan yakuniy kurash — texnika). Har bir bosqichning o'z qoidalari va tamoyillari bor."]),("Amaliy o'yinlar va turnir tashkil etish",["Amaliy o'yinlar: klassik o'yin (har bir o'yinchiga 90 daqiqa + qo'shimcha), rapid (15-60 daqiqa), blits (3-10 daqiqa), bullet (1-2 daqiqa). Talabalar uchun blits va rapid formatlar qulay — ular vaqtni tejaydi va qiziqarli.","Turnir formatlari: round-robin (har kim har kim bilan o'ynaydi — kichik guruhlar uchun), swiss system (shveytsariya tizimi — natijasi yaqin o'yinchilar o'ynaydi — ko'p ishtirokchi uchun), knockout (chiqarish tizimi). Har bir format o'z holati uchun mos.","Turnir tashkil etish: ishtirokchilarni ro'yxatga olish, jadval tuzish, vaqt nazorati (shaxmat soati), yozish jadvali, natijalar jadvali. Talabalar nafaqat o'ynash, balki tashkil etishni ham o'rganadilar. Bu tashkilotchilik ko'nikmalarini rivojlantiradi."])],})

